const pages = [];
let fullText = "";

items.forEach((it, idx) => {
  const resp = it.json;
  let text = "";

  if (resp.output_text) {
    text = resp.output_text;
  } else if (resp.output) {
    for (const o of resp.output) {
      if (o.content) {
        for (const c of o.content) {
          if (c.type === 'output_text' && c.text) {
            text += c.text + "\n";
          }
        }
      }
    }
  }

  text = text.trim();

  pages.push({
    page: idx,    // page 0,1,2...
    text
  });

  // Giữ lại phần này nếu bạn vẫn muốn đánh dấu trang trong fullText
  fullText += `--- Page ${idx} ---\n${text}\n\n`;
});

// THAY ĐỔI Ở ĐÂY: Chỉ trả về một object với key là 'text'
return {
  text: fullText.trim()
};
